const job = $('Read Enriched Jobs').item.json;
const resumeRows = $('Read Master Resume').all().map(i => i.json);
const masterResume = resumeRows.map(r => r.content || r.text || r.section || JSON.stringify(r)).join('\n\n');
return [{ json: {
  ...job,
  master_resume: masterResume.slice(0, 6000)
} }];

parameters.jsonBody:
={
  "messages": [
    {
      "role": "system",
      "content": "You are an expert career strategist and hiring signal analyst.

Evaluate whether this job is relevant to the candidate based only on the provided resume evidence, job description, and company context.

Return strict JSON with: job_id, fit_score (0-100 integer), decision (reject|needs_review|generate_resume), rationale (string), matched_requirements (array of strings), missing_requirements (array of strings), resume_evidence (array of strings), company_signals (array of strings), risk_flags (array of strings).

Scoring guide:
- 90-100: excellent match
- 80-89: strong match, generate resume
- 65-79: possible match, needs human review
- 40-64: weak match, reject
- 0-39: irrelevant

Do not inflate scores. Do not assume skills not in the resume."
    },
    {
      "role": "user",
      "content": "JOB ID: {{$json.job_id}}

JOB TITLE: {{$json.title}}
COMPANY: {{$json.company_name}}
LOCATION: {{$json.location}}

JOB DESCRIPTION:
{{$json.description.slice(0, 4000)}}

COMPANY RESEARCH:
{{typeof $json.company_research === 'string' ? $json.company_research.slice(0, 2000) : JSON.stringify($json.company_research || {}).slice(0, 2000)}}

MASTER RESUME:
{{$json.master_resume}}"
    }
  ],
  "response_format": { "type": "json_object" },
  "max_tokens": 1500
}

parameters.jsCode:
const job = $('Prepare Fit Input').item.json;
const raw = $json.choices?.[0]?.message?.content || '{}';
let fit;
try { fit = JSON.parse(raw); } catch (e) { fit = { fit_score: 0, decision: 'needs_review', parse_error: true }; }
return [{ json: { ...job, fit } }];

parameters.jsonBody:
={
  "messages": [
    {
      "role": "system",
      "content": "You are an expert resume writer for senior technical and process improvement roles.

Create a tailored resume for the target job using only truthful information from the master resume evidence.

Return strict JSON with: job_id, document_title, resume_html (clean semantic HTML, ATS-friendly, no images/scripts/external CSS), resume_markdown, tailoring_rationale, keywords_used (array), risks_or_gaps (array).

Rules:
- Do NOT fabricate employers, dates, titles, metrics, certifications, tools, or achievements
- Rephrase and reorder truthful experience to match the job
- Prioritize skills and projects relevant to the job description
- Use company research to tune positioning, not to invent experience
- Keep concise and ATS-friendly"
    },
    {
      "role": "user",
      "content": "JOB ID: {{$json.job_id}}
JOB TITLE: {{$json.title}}
COMPANY: {{$json.company_name}}

JOB DESCRIPTION:
{{$json.description.slice(0, 4000)}}

COMPANY RESEARCH:
{{typeof $json.company_research === 'string' ? $json.company_research.slice(0, 2000) : JSON.stringify($json.company_research || {}).slice(0, 2000)}}

FIT ANALYSIS:
Score: {{$json.fit.fit_score}}
Matched: {{JSON.stringify($json.fit.matched_requirements || [])}}
Missing: {{JSON.stringify($json.fit.missing_requirements || [])}}

MASTER RESUME:
{{$json.master_resume}}"
    }
  ],
  "response_format": { "type": "json_object" },
  "max_tokens": 3000
}

parameters.jsCode:
const job = $('Parse Fit Score').item.json;
const raw = $json.choices?.[0]?.message?.content || '{}';
let resume;
try { resume = JSON.parse(raw); } catch (e) { resume = { parse_error: true, document_title: `Resume - ${job.title} - ${job.company_name}` }; }
return [{ json: {
  ...job,
  resume_markdown: resume.resume_markdown || '',
  resume_html: resume.resume_html || '',
  tailoring_rationale: resume.tailoring_rationale || '',
  status: 'needs_review',
  fit_score: job.fit.fit_score,
  fit_decision: job.fit.decision,
  fit_rationale: job.fit.rationale || '',
  matched_requirements: (job.fit.matched_requirements || []).join(', '),
  missing_requirements: (job.fit.missing_requirements || []).join(', '),
  updated_at: new Date().toISOString()
} }];

const job = $json;
return [{ json: {
  ...job,
  status: job.fit.fit_score >= 65 ? 'needs_review' : 'rejected',
  fit_score: job.fit.fit_score,
  fit_decision: job.fit.decision,
  fit_rationale: job.fit.rationale || '',
  matched_requirements: (job.fit.matched_requirements || []).join(', '),
  missing_requirements: (job.fit.missing_requirements || []).join(', '),
  updated_at: new Date().toISOString()
} }];
